double** vertices;
int* verticesSizes;
int** indices;
int* indicesSizes;
int elementCount = simImportMesh(1, "d:\\example.dxf", 0, 0.0001, 1.0, &vertices,
                                 &verticesSizes, &indices, &indicesSizes, null, null);
if (elementCount > 0)
{
    const double grey[3] = {0.5, 0.5, 0.5};
    for (int i = 0; i < elementCount; i++)
    {
        int shapeHandle = simCreateShape(2, 20.0 * 3.1415 / 180.0, vertices[i],
                               verticesSizes[i], indices[i], indicesSizes[i], null,
                               null, null, null);
        simSetShapeColor(shapeHandle, "", sim_colorcomponent_ambient, grey);
        simReleaseBuffer((char*)indices[i]);
        simReleaseBuffer((char*)vertices[i]);
    }
    simReleaseBuffer((char*)indicesSizes);
    simReleaseBuffer((char*)indices);
    simReleaseBuffer((char*)verticesSizes);
    simReleaseBuffer((char*)vertices);
}

param.description:
name of a color. Can be null, but if a name is provided, only shapes (or sub-entities of them) with a same color name will be modified. If colorName is 

    @compound

, then all individual colors of a compound shape can be set at once.
